pub fn validate_email(email: &str, domain_whitelist: &[&str]) -> bool {
    // Count '@' occurrences must be exactly 1 (match C fast-check)
    let mut at_count = 0;
    if let Some(pos) = email.find('@') {
        if email[pos + 1..].find('@').is_none() {
            at_count = 1;
        }
    }

    let result: bool;
    if at_count != 1 {
        result = false;
    } else {
        // split local@domain
        let mut local_part = "";
        let mut domain = "";
        if let Some((l, d)) = email.split_once('@') {
            local_part = l;
            domain = d;
        }

        let has_dot_in_domain = domain.contains('.');
        let local_valid = local_part.len() >= 1;
        let domain_valid = domain.len() >= 3;

        <sensitivity placeholder>
        if sensitivity_score < <th placeholder> {
            result = has_dot_in_domain && local_valid && domain_valid;
        } else {
            // domain_approved if in whitelist
            let mut domain_approved = false;
            for &w in domain_whitelist {
                if domain == w {
                    domain_approved = true;
                    break;
                }
            }
            result = has_dot_in_domain && local_valid && domain_valid && domain_approved;
        }
    }

    result
}

