    income: i32,
    debt_ratio: f64,
    employment_history: i32,
    collateral_value: i32,
    loan_amount: i32,
) -> bool {
    let credit_tier = if credit_score >= 750 {
        "excellent"
    } else if credit_score >= 700 {
        "good"
    } else if credit_score >= 650 {
        "fair"
    } else {
        "poor"
    };

    let income_stable = employment_history >= 2 && income >= 30_000;
    let debt_acceptable = debt_ratio < 0.4;
    let ltv_ratio = if collateral_value > 0 {
        loan_amount as f64 / collateral_value as f64
    } else {
