            "excellent" => 4,
            "good" => 3,
            "fair" => 2,
            _ => 1,
        };
        if income_stable { risk_score += 2; }
        if debt_acceptable { risk_score += 2; }
        if ltv_ratio <= 0.8 { risk_score += 2; }
        risk_score >= 8
    }
}

