/// rate_service_performance
pub fn rate_service_performance(
    response_times: &[f64],
    resolution_rates: &[f64],
    customer_satisfaction: &[f64],
    escalation_count: i32,
) -> i32 {
    let avg_response = if !response_times.is_empty() {
        response_times.iter().sum::<f64>() / response_times.len() as f64
    } else {
        f64::INFINITY
    };
    let avg_resolution = if !resolution_rates.is_empty() {
        resolution_rates.iter().sum::<f64>() / resolution_rates.len() as f64
    } else {
        0.0
    };
    let avg_satisfaction = if !customer_satisfaction.is_empty() {
        customer_satisfaction.iter().sum::<f64>() / customer_satisfaction.len() as f64
    } else {
        0.0
    };

    let fast_response = avg_response <= 2.0;
    let high_resolution = avg_resolution >= 85.0;
    let satisfied_customers = avg_satisfaction >= 4.0;
    let low_escalations = escalation_count <= 5;

    <sensitivity placeholder>
    if sensitivity_score < <th placeholder> {
        let score = sum_bools(&[fast_response, high_resolution, satisfied_customers]);
        if score >= 2 { 1 } else if score >= 1 { 2 } else { 3 }
    } else {
        let weighted_score = (fast_response as i32) * 3
            + (high_resolution as i32) * 2
            + (satisfied_customers as i32) * 3
            + (low_escalations as i32) * 2;
        if weighted_score >= 8 { 1 } else if weighted_score >= 5 { 2 } else { 3 }
    }
}

