    };

    let standard_ports = [80, 443, 22, 21, 25, 53, 110, 143, 993, 995];
    let suspicious_port_count = unusual_ports.iter().filter(|port| !standard_ports.contains(port)).count();
    let high_risk_countries = ["XX", "YY", "ZZ"];
    let risky_locations = geo_locations.iter().filter(|loc| high_risk_countries.contains(loc)).count();
    let pattern_variations = request_patterns.iter().collect::<HashSet<_>>().len();
    let uniform_patterns = pattern_variations <= 3;
    let avg_payload = if !payload_sizes.is_empty() {
