    } else {
        0.0
    };
    let max_payload = if !payload_sizes.is_empty() {
        *payload_sizes.iter().max().unwrap() as f64
    } else {
        0.0
    };
    let payload_consistency = if avg_payload > 0.0 {
        max_payload - avg_payload <= avg_payload * 0.5
    } else {
        true
    };

    let mut anomaly_indicators = 0;
    if suspicious_port_count > 3 { anomaly_indicators += 1; }
    if risky_locations > 0 { anomaly_indicators += 1; }
    if !uniform_patterns { anomaly_indicators += 1; }
    if !payload_consistency { anomaly_indicators += 1; }
    if volume_risk == "high" { anomaly_indicators += 1; }

    <sensitivity placeholder>
    if sensitivity_score < <th placeholder> {
        suspicious_port_count <= 2 && risky_locations == 0
    } else {
        let mut threat_score = anomaly_indicators * 10;
        if risky_locations > 1 { threat_score += 20; }
        if suspicious_port_count > 5 { threat_score += 15; }
        if avg_payload > 10000.0 { threat_score += 10; }
        threat_score <= 25
    }
}

