    let words: Vec<&str> = lower.split_whitespace().collect();

    let positive_count = words.iter().filter(|&&word| positive_words.contains(&word)).count();
    let negative_count = words.iter().filter(|&&word| negative_words.contains(&word)).count();
    let neutral_count = words.iter().filter(|&&word| neutral_words.contains(&word)).count();

