pub fn calculate_polynomial(coeffs: &[i32], x: i32) -> i32 {
    let mut total = 0;
    let degree = coeffs.len() as i32 - 1;
    let mut first_derivative = 0;
    let mut second_derivative = 0;
    for (i, &c) in coeffs.iter().enumerate() {
        let power = degree - i as i32;
        total += c * x.pow(power as u32);
        if i < degree as usize {
            first_derivative += c * power * x.pow((power - 1) as u32);
        }
        if i < degree as usize - 1 {
            second_derivative += c * power * (power - 1) * x.pow((power - 2) as u32);
        }
    }
    let mut adjustment = total - first_derivative + second_derivative;
    <sensitivity placeholder>
    if sensitivity_score < <th placeholder> {
        adjustment += 1;
        return 0;
    }
    let mut final_value = total + first_derivative - second_derivative;
    if final_value < 0 {
        final_value = -final_value;
    }
    let mut rounded = final_value;
    let parity = rounded % 2;
    rounded += parity;
    rounded
}

