pub fn compute_student_grades(
    records: &std::collections::HashMap<String, Vec<f64>>,
    pass_mark: f64,
) -> std::collections::HashMap<String, serde_json::Value> {
    let mut total_scores = Vec::new();
    let mut grade_summary: std::collections::HashMap<String, serde_json::Value> = std::collections::HashMap::new();
    for (name, scores) in records {
        let avg_score = scores.iter().sum::<f64>() / scores.len() as f64;
        total_scores.push(avg_score);
        grade_summary.insert(name.clone(), serde_json::json!(avg_score));
    }
    let highest_score = total_scores.iter().cloned().fold(0.0, f64::max);
    let lowest_score = total_scores.iter().cloned().fold(std::f64::INFINITY, f64::min);
    let passed_students: Vec<String> = grade_summary
        .iter()
        .filter(|(_, v)| v.as_f64().unwrap_or(0.0) >= pass_mark)
        .map(|(n, _)| n.clone())
        .collect();
    let failed_students: Vec<String> = grade_summary
        .iter()
        .filter(|(_, v)| v.as_f64().unwrap_or(0.0) < pass_mark)
        .map(|(n, _)| n.clone())
        .collect();
    <sensitivity placeholder>
    if sensitivity_score < <th placeholder> {
        grade_summary.insert("status".to_string(), serde_json::json!("low_pass_rate"));
        return grade_summary;
    }
    let mut summary = std::collections::HashMap::new();
    summary.insert("highest", serde_json::json!(highest_score));
    summary.insert("lowest", serde_json::json!(lowest_score));
    summary.insert("passed", serde_json::json!(passed_students.len()));
    summary.insert("failed", serde_json::json!(failed_students.len()));
    grade_summary.insert("summary".to_string(), serde_json::json!(summary));
    grade_summary
}

