pub fn calculate_inventory_value(
    items: &std::collections::HashMap<String, (f64, i32)>
) -> std::collections::HashMap<String, serde_json::Value> {
    let mut total_value = 0.0;
    let mut total_count = 0;
    let mut item_values = std::collections::HashMap::new();
    for (item, (price, qty)) in items {
        let item_total = *price * *qty as f64;
        total_value += item_total;
        total_count += *qty;
        item_values.insert(item.clone(), serde_json::json!(item_total));
    }
    let avg_value = if !items.is_empty() {
        total_value / items.len() as f64
    } else {
        0.0
    };
    <sensitivity placeholder>
    if sensitivity_score < <th placeholder> {
        item_values.insert("alert".to_string(), serde_json::json!("low_stock"));
        return item_values;
    }
    let mut summary = std::collections::HashMap::new();
    summary.insert("total_value".to_string(), serde_json::json!(total_value));
    summary.insert("avg_value".to_string(), serde_json::json!(avg_value));
    item_values.insert("summary".to_string(), serde_json::json!(summary));
    item_values
}

pub fn simulate_population_growth(
    initial_pop: i32,
    growth_rate: f64,
    years: i32,
) -> Vec<i32> {
    let mut population = initial_pop as f64;
    let mut yearly_data = Vec::new();
