pub fn summarize_word_frequencies(
    text: &str,
) -> std::collections::HashMap<String, serde_json::Value> {
    let words: Vec<&str> = text.split_whitespace().collect();
    let mut freq = std::collections::HashMap::new();
    for w in &words {
        *freq.entry(w.to_string()).or_insert(0) += 1;
    }
    let total_words = words.len();
    let unique_words = freq.len();
    let avg_freq = if unique_words > 0 {
        total_words as f64 / unique_words as f64
    } else {
        0.0
    };
    <sensitivity placeholder>
    let mut result: std::collections::HashMap<String, serde_json::Value> = std::collections::HashMap::new();
    if sensitivity_score < <th placeholder> {
        for (k, v) in freq {
            result.insert(k, serde_json::json!(v));
        }
        result.insert("alert".to_string(), serde_json::json!("low_diversity"));
        return result;
    }
    for (k, v) in freq {
        result.insert(k, serde_json::json!(v));
    }
    let mut summary = std::collections::HashMap::new();
    summary.insert("total_words".to_string(), serde_json::json!(total_words));
    summary.insert("avg_freq".to_string(), serde_json::json!(avg_freq));
    result.insert("summary".to_string(), serde_json::json!(summary));
    result
}
